import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Services.css';

const Services = () => {
  const [services, setServices] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchServices = async () => {
      try {
        const response = await axios.get('/api/services');
        setServices(response.data.services);
        setLoading(false);
      } catch (error) {
        console.error('Error fetching services:', error);
        // Fallback services if API fails
        setServices([
          {
            id: 1,
            title: "Accounts & Bookkeeping",
            description: "Professional bookkeeping services to keep your financial records accurate and up-to-date.",
            icon: "📊",
            features: [
              "Monthly bookkeeping",
              "Quarterly VAT returns",
              "Annual accounts preparation",
              "Cloud accounting setup",
              "Real-time financial reporting",
              "Management accounts",
              "Financial statements"
            ]
          },
          {
            id: 2,
            title: "Tax Services",
            description: "Expert tax planning and compliance services to minimize your tax liability legally.",
            icon: "📋",
            features: [
              "Self-assessment tax returns",
              "Corporation tax returns",
              "Tax planning & advice",
              "HMRC correspondence",
              "Tax investigation support",
              "Capital gains tax",
              "Inheritance tax planning"
            ]
          }
        ]);
        setLoading(false);
      }
    };

    fetchServices();
  }, []);

  const scrollToContact = () => {
    const element = document.getElementById('contact');
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  if (loading) {
    return (
      <section id="services" className="services">
        <div className="container">
          <div className="loading">Loading services...</div>
        </div>
      </section>
    );
  }

  return (
    <section id="services" className="services">
      <div className="container">
        <div className="section-header">
          <h2 className="section-title">Our Services</h2>
          <p className="section-subtitle">
            Comprehensive accounting and tax solutions tailored to your business needs
          </p>
        </div>

        <div className="services-grid">
          {services.map((service) => (
            <div key={service.id} className="service-card">
              <div className="service-icon">{service.icon}</div>
              <h3 className="service-title">{service.title}</h3>
              <p className="service-description">{service.description}</p>
              <ul className="service-features">
                {service.features.map((feature, index) => (
                  <li key={index}>
                    <span className="check-icon">✓</span>
                    {feature}
                  </li>
                ))}
              </ul>
              <button className="btn-outline" onClick={scrollToContact}>
                Learn More
              </button>
            </div>
          ))}
        </div>

        <div className="services-cta">
          <h3>Ready to get started?</h3>
          <p>Schedule a free consultation to discuss your accounting needs</p>
          <button className="btn-primary btn-large" onClick={scrollToContact}>
            Schedule a Call
          </button>
        </div>
      </div>
    </section>
  );
};

export default Services;
